import { AsyncStorage } from 'react-native';
import CryptoJS from 'crypto-js';
import Config from './config'; // Assuming you have a config file with encryption key

// Function to encrypt text
export const encrypt = (text) => {
    return CryptoJS.AES.encrypt(text, Config.ENCRYPTION_KEY).toString();
}

// Function to decrypt text
export const decrypt = (cipherText) => {
    let bytes  = CryptoJS.AES.decrypt(cipherText, Config.ENCRYPTION_KEY);
    return bytes.toString(CryptoJS.enc.Utf8);
}

// Function to save item in AsyncStorage after encrypting it
export const saveItem = async (key, value) => {
    try {
        await AsyncStorage.setItem(key, encrypt(value));
    } catch (error) {
        console.log('Error saving data', error);
    }
}

// Function to get item from AsyncStorage after decrypting it
export const getItem = async (key) => {
    try {
        let value = await AsyncStorage.getItem(key);
        return decrypt(value);
    } catch (error) {
        console.log('Error getting data', error);
    }
}